    """从消息文本提取干净的标题"""
    # 先清理
    clean = clean_message_text(text)
    lines = [l for l in clean.split('\n') if l.strip()]

    # 找第一行不是 JSON 的内容
    for line in lines:
        line = line.strip()
        if line.startswith('{') or line.startswith('```'):
            continue
        if line.startswith('**') or line.startswith('#'):
            continue
        # 过滤掉纯 JSON
        if line.startswith('{') and '"' in line:
            try:
                json.loads(line)
                continue  # 是 JSON，跳过
            except:
                pass
        if len(line) > 3:
            return line[:max_len].replace('/', '-').replace('#', '')

    return lines[0][:max_len] if lines else "对话"

