def extract_clean_title(text: str, max_len: int = 40) -> str:
    """从消息文本提取干净的标题（用于文件名和笔记标题）"""
    # 先做基本清理，去掉 JSON 元数据块
    # 去掉 ```json ... ``` 包裹的块
    cleaned = re.sub(r'```json\b.*?```', '', text, flags=re.DOTALL)
    # 去掉 ``` 单独出现的行
    cleaned = re.sub(r'```', '', cleaned)
    # 去掉 { 开头的元信息行直到第一个真正的文字行
    lines = cleaned.split('\n')

    meaningful_lines = []
    in_json_block = False
    for line in lines:
        stripped = line.strip()
        if not stripped:
            continue
        # 检测 JSON 对象开始
        if stripped.startswith('{') and '"' in stripped and not in_json_block:
            in_json_block = True
            continue
        if in_json_block:
            if stripped == '}' or stripped.startswith('}'):
                in_json_block = False
            continue
        # 跳过纯符号/元信息行
        if stripped.startswith('**') and stripped.endswith('**'):
            continue
        if stripped.startswith('#'):
            continue
        if re.match(r'^"[\w-]+"\s*:', stripped):
            # JSON 属性行
            continue
        meaningful_lines.append(stripped)

    # 取第一段有意义的文字
    for line in meaningful_lines:
        line = line.strip()
        if len(line) < 2:
            continue
        # 跳过消息标识行
        if '[message_id' in line or '[UNTRUSTED' in line:
            continue
        # 跳过文件路径行
        if '/.openclaw/' in line or '.md' in line:
            continue
        # 跳过 heartbeat/system 指令行
        if 'HEARTBEAT' in line or 'ACTIVATE' in line:
            continue

        result = line[:max_len].replace('/', '-').replace('#', '').strip(' "\':;,。')
        if result:
            return result

    return "对话"

