def get_conversation_title(snippet: list) -> str:
    """从对话片段中提取标题：优先用最后一条用户消息（真正的用户提问），次选用第一条"""
    # 找所有用户消息
    user_msgs = [m for m in snippet if m['role'] == 'user']
    if not user_msgs:
        return "对话"

    # 过滤掉纯系统心跳消息（只看消息长度，排除纯JSON或指令）
    def is_meaningful_user_msg(msg):
        content = msg.get('content', '')
        if len(content) < 5:
            return False
        # 排除 JSON 元信息块（以 { 开头）
        if content.strip().startswith('{'):
            return False
        # 排除 system/heartbeat 消息
        first_line = content.split('\n')[0] if '\n' in content else content
        if 'HEARTBEAT' in content or 'ACTIVATE_TASK' in content:
            return False
        if '<active-task' in content:
            return False
        if first_line.startswith('<'):
            return False
        return True

    meaningful = [m for m in user_msgs if is_meaningful_user_msg(m)]

    if meaningful:
        # 用最后一条有意义的用户消息（通常是当前对话的核心问题）
        chosen = meaningful[-1]
    else:
        chosen = user_msgs[-1]

    content = chosen.get('content', '')

    # 去掉 URL
    content_no_url = re.sub(r'https?://\S+', '', content).strip()
    # 取第一行
    first_line = content_no_url.split('\n')[0] if '\n' in content_no_url else content_no_url
    # 去掉残留前缀（如 "张玲:"）
    if ':' in first_line and not first_line[0].isalpha():
        first_line = first_line.split(':', 1)[-1].strip()

    if first_line and len(first_line) > 1:
        return first_line[:40].replace('/', '-').replace('#', '').strip(' "\':;,。')

    return "对话"

