    """读取同日收盘价"""
    # 尝试从 a_stock_history 读取
    hist_path = PROJECT_ROOT / "data" / "a_stock_history.csv"
    if hist_path.exists():
        df = pd.read_csv(hist_path, usecols=["trade_date", "ts_code", "close"])
        date_col = "trade_date"
    else:
        # 尝试从 qbot_ashare 读取
        qbot_dir = PROJECT_ROOT / "data" / "processed" / "qbot_ashare"
        if qbot_dir.exists():
            files = list(qbot_dir.glob("*.csv"))[:100]  # 采样
            records = []
            for f in files:
                try:
                    sub = pd.read_csv(f, usecols=["date", "close"])
                    sub["ts_code"] = f.stem
                    records.append(sub)
                except:
                    pass
            if records:
                df = pd.concat(records, ignore_index=True)
                df = df.rename(columns={"date": "trade_date"})
                date_col = "trade_date"
            else:
                df = None
        else:
            df = None

